//@arg max_limit int Maximum memory entries
//@arg threshold string Memory importance threshold
//@arg sim_threshold string Similarity threshold percentage
//@arg cold_start_scope_preset string Cold-start scope preset
//@arg cold_start_history_limit int Cold-start history limit
//@arg debug string Enable recent-turn debug capture/export, default false: true/false
//@arg secret_knowledge_enabled string Enable secret knowledge guard: true/false
//@arg entity_knowledge_vault_enabled string Enable per-entity POV knowledge guard: true/false
//@arg rp_long_term_memory_enabled string Enable RP long-term continuity ledger: true/false
//@arg rp_long_term_llm_enrichment string Enrich RP long-term memory in the existing maintenance LLM pass: true/false
//@arg rp_long_term_injection_max_chars int Maximum RP long-term continuity injection characters
//@arg rp_long_term_long_ttl int Turn TTL for durable long-term RP memories
//@arg rp_long_term_medium_ttl int Turn TTL for medium-term RP memories
//@arg activity_dashboard string Realtime activity overlay: off|compact|full
//@arg background_maintenance_delay_ms int Delay background maintenance after afterRequest in ms
//@arg after_request_maintenance_mode string afterRequest maintenance mode: background|foreground
//@arg after_request_foreground_timeout_ms int Foreground afterRequest maintenance timeout in ms
//@arg after_request_analysis_budget_ms int Bounded wall-clock budget for detached afterRequest analysis in ms (default 480000, max 900000)
//@arg after_request_parallel_analysis string Split afterRequest LLM analysis into parallel packet + maintenance workers: true/false
//@arg libra_injection_mode string LIBRA injection mode: direct|hybrid|lorebook_projection
//@arg libra_projection_always_active string Enable LIBRA projection lorebook entries: true|false
//@arg libra_projection_max_chars int Maximum characters per LIBRA projection lorebook entry
//@arg libra_projection_recall_bundle string LIBRA recall bundle projection: off|projection_only|hybrid|always
//@arg internal_data_language_mode string LIBRA internal generated data language: off|fixed_korean|fixed_english|follow_main_response
//@arg internal_data_language_debug string Enable internal data language normalization diagnostics: true|false
//@arg manual_ooc_pause string Fully pause LIBRA and bypass all request-time work: true/false
//@arg entity_blocklist string Comma/newline separated blocked entity names
//@arg bypass_aux_requests string Skip LIBRA for auxiliary/plugin requests (memory/emotion/translate and explicit helper prompts): true/false
//@arg response_streaming_compat_enabled string Commit LIBRA data after RisuAI response streaming: true/false
//@arg hayaku_interop_enabled string auto|true|false — auto is recommended; true/false force the compatibility request
//@arg hayaku_packet_rescue_mode string auto|off|detect|safe|full — auto uses the optimized detect policy
//@arg hayaku_packet_rescue_delay_ms int 0 uses the automatic delay; 500-15000 forces milliseconds
//@arg emotion_enabled string Enable emotion tracking: true/false
//@arg nsfw_enabled string Enable mature creative-writing guidance: true/false
//@arg nsfw_mode string NSFW guidance mode: off|soft|direct|explicit
//@arg nsfw_guidance_prompt_enabled string Include NSFW guidance prompt when nsfw_mode is active: true/false
//@arg assistant_prefill_enabled string Include assistant prefill block for NSFW/autocontinue contexts: true/false
//@arg gc_batch_size int GC batch size
//@arg memory_preset string Memory preset
//@arg world_adjustment_mode string World adjustment mode
//@arg world_additional_enabled string Enable World Additional/Changer layer: true/false
//@arg world_additional_mode string World Additional force mode: off|soft|firm|hard
//@arg world_additional_max_per_request int Max World Additional directives injected per request
//@arg world_additional_user_impact_limit string Max user impact: none|ambient|soft|direct|major
//@arg world_additional_auto_integrate string Auto-integrate manifested world/character additions: true/false
//@arg world_canon_custom_text string User-authored LIBRA canon DB reflection directive text
//@arg world_canon_custom_force string Treat LIBRA canon DB reflection directive as authoritative user design input: true/false
//@arg world_additional_custom_text string User-authored World Additional directive text
//@arg world_additional_custom_force string Force World Additional directive even when no generated directive exists: true/false
//@arg section_world_inference_enabled string Enable section world inference: true/false
